package dev.shreeman.benchmark

import android.content.Context
import android.os.Handler
import android.os.Looper
import kotlinx.coroutines.flow.MutableSharedFlow
import kotlinx.coroutines.flow.SharedFlow
import kotlinx.coroutines.flow.asSharedFlow
import nitro.benchmark_module.*
import kotlin.math.cos
import kotlin.math.sin

/// Native implementation of HybridBenchmarkSpec.
/// This file is yours to edit — the interface is generated by `nitrogen generate`.
class BenchmarkImpl(private val context: Context) : HybridBenchmarkSpec {

    private val _dataStream = MutableSharedFlow<BenchmarkPoint>(extraBufferCapacity = 1)
    private val _boxStream = MutableSharedFlow<BenchmarkBox>(extraBufferCapacity = 1)

    private var angle = 0.0
    private val handler = Handler(Looper.getMainLooper())

    private val emitter = object : Runnable {
        override fun run() {
            angle += 0.05

            // Box Stream
            val r = ((sin(angle) + 1.0) * 127).toLong()
            val g = ((sin(angle + 2.0) + 1.0) * 127).toLong()
            val b = ((sin(angle + 4.0) + 1.0) * 127).toLong()
            val color = 0xFF000000 or (r shl 16) or (g shl 8) or b

            val width = 100.0 + sin(angle * 0.5) * 50.0
            val height = 100.0 + cos(angle * 0.5) * 50.0

            _boxStream.tryEmit(BenchmarkBox(color, width, height))

            // Data Stream
            _dataStream.tryEmit(BenchmarkPoint(sin(angle), cos(angle)))

            handler.postDelayed(this, 16) // ~60 FPS
        }
    }

    init {
        handler.post(emitter)
    }

    override fun add(a: Double, b: Double): Double = a + b

    override fun addFast(a: Double, b: Double): Double = a + b

    override suspend fun getGreeting(name: String): String = "Hello, $name!"

    override fun scalePoint(point: BenchmarkPoint, factor: Double): BenchmarkPoint {
        return BenchmarkPoint(point.x * factor, point.y * factor)
    }

    override suspend fun computeStats(iterations: Long): BenchmarkStats {
        return BenchmarkStats(iterations, 1.5, 1.2, 2.5)
    }

    override fun sendLargeBuffer(buffer: ByteArray): Int {
        var sum = 0
        // Access memory to prevent optimization
        for (i in buffer.indices step 4096) {
           sum += buffer[i].toInt()
        }
        return buffer.size
    }

    override val dataStream: SharedFlow<BenchmarkPoint> = _dataStream.asSharedFlow()
    override val boxStream: SharedFlow<BenchmarkBox> = _boxStream.asSharedFlow()
}
